import React from "react"
import { properties } from '../../properties/properties.js'
import Select from 'react-select'
import Popup from 'reactjs-popup'
import 'reactjs-popup/dist/index.css'
import {Tab, Tabs, TabList, TabPanel} from 'react-tabs'
import 'react-tabs/style/react-tabs.css'


class CyberAdmin extends React.Component {


    constructor(props) {
        super(props);
        this.state = { screen: 1, teamList: [], permission: false
        };

    }

    componentDidMount() {

        this.setState({screen: 0});

        let headers = new Headers();

        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');


        var backUrl = properties.backend + `cyberraptor/algorithms`

        fetch(backUrl, {
          "method": "GET",
          headers: headers
        })
        .then(response => response.json())
        .then(response => {
            this.setState({permission: response.permission})
            this.setState({screen: 1})
            this.setState({teamList: response.teamList})
        })
        .catch(err => {
          console.log(err);
        });

    }



    handleTeamEnable = (event) => {

var message = event.target.checked ? "enable" : "disable"

        const confirmed = window.confirm("Are you sure you want to " + message  + " "  + event.target.value.toLowerCase() + "?");
        if (confirmed) {
            this.setState({screen: 0});

            let headers = new Headers();

            headers.append('Content-Type', 'application/json');
            headers.append('Accept', 'application/json');


            var backUrl = properties.backend + `cyberraptor/enableteam`
            fetch(backUrl, {
              "method": "POST",
              headers: headers, 
              body: JSON.stringify({systemid: event.target.id, enable: event.target.checked})
            })
            .then(response => response.json())
            .then(response => {
                if (response.message != "success") {
                    this.setState({screen: 1})
                    alert(response.message)

                } else {
                    /*
                    this.setState({result: response.avaliableAlgorthim})
                    this.setState({distributionResult: response.distributionAlgorithm})
                    this.setState({mainStep: response.mainStep})
                    this.setState({permission: response.permission})
                    */

                    this.setState({teamList: response.teamList})
                    this.setState({screen: 1})


                    alert(event.target.value.toLowerCase() + " has been " + message + "d.")
                }
            })
            .catch(err => {
              console.log(err);
            });
        } else {
            event.target.checked = !event.target.checked
        }
      };



    render() {


        var header = "Loading ..."
        var content = []
        var borderStyleString = "1px solid black"
        var divStyleString = {marginTop: "10px"}
        var marginTop = "10px"
        var redColor = {color: "red"}
        var divStyleDoubleString = {marginTop: "20px"}



        if (!this.state.permission) {

            content.push(<div>You don't have permission for this application! Please contact Keith Siu - keith.siu@ucsf.edu</div>)

            header = ""
        }


        var teamContent = []

        if (this.state.screen == 1 && this.state.permission) {

            //content.push(<PopupExample></PopupExample>)


            header = ""
            var headerColor = "navy"
            var headerTextColor = "#FFFFFF"





            var teamResult = this.state.teamList

            var teamContentTemp = []
            for (var index99 in teamResult) {

                var singleTeamResult = teamResult[index99]

                teamContentTemp.push(<tr>
                    <td style={{border:  borderStyleString, padding: '10px'}}>{singleTeamResult.name}</td>

                    <td style={{border:  borderStyleString, padding: '10px'}}><input type="checkbox" defaultChecked={singleTeamResult.enable} id={singleTeamResult.systemid} onChange={this.handleTeamEnable} value={singleTeamResult.name}/></td>
                </tr>)

            }


            teamContent.push(<table><tr><td style={{border:  borderStyleString, fontSize: '20px', padding: '5px', backgroundColor: headerColor, color: headerTextColor, textAlign: "center"}}>Team</td><td style={{border:  borderStyleString, fontSize: '20px', padding: '5px', backgroundColor: headerColor, color: headerTextColor, textAlign: "center"}}>Enable</td></tr>{teamContentTemp}</table>)
        }


        if (this.state.screen == 1 && this.state.permission) {


            content.push(<div><div style={{marginTop: "30px"}}><h2>Enable or Disable Team</h2></div>
                 <div style={{marginTop: "30px"}}>{teamContent}</div></div>)

        }






        return (
            <div style={{minHeight: "500px", marginLeft: "50px", marginRight: "50px"}}><h2 className="display-4 text-center">{header}</h2>{content}
            </div>
        );


      }


}


export default CyberAdmin
